final _dnTok = RegExp(r'DN\s?(\d+)|(\d+)/(\d+)|(\d+)["׳״]|\b(32|40|50|60|75|90|110|130|160|200)\b');

/// Normalise unicode inch fractions so the size engine recognises them
/// (צעד 22): 1¼ → 1.25 · 1½ → 1.5 · 2½ → 2.5 · ¾ → 0.75 ...
String _expandInchFractions(String w) => w
    .replaceAll('¼', '.25')
    .replaceAll('½', '.5')
    .replaceAll('¾', '.75')
    .replaceAll('⅛', '.125')
    .replaceAll('⅜', '.375')
    .replaceAll('⅝', '.625')
    .replaceAll('⅞', '.875');

/// Atomic DN connection sizes from a product name (e.g. "75/50" → [75,50],
/// "DN50" → [50]). Dimension-context only; ignores pack qty / length.
List<String> lipskeyConnectionSizes(String name) {
  final out = <String>{};
  for (final raw in name.split(RegExp(r'\s+'))) {
    var w = _expandInchFractions(raw.trim());

    // N×M / NxM format (HDPE compression fittings: pipe-size × thread-size).
    // e.g. "16×1/2"" → both sides: [16, .5]. Without this, the ½" end is
    // invisible and canConnect / size-overlap checks miss the thread side.
    final crossMatch = RegExp(r'^(\d{1,3})[×x](.+)$').firstMatch(w);
    if (crossMatch != null) {
      out.add(crossMatch.group(1)!);
      // Also extract the right-hand side — may be "1/2"", "3/4"", "16", etc.
      // so we strip quotes, expand Unicode fractions, then parse.
      var rhs = crossMatch.group(2)!.replaceAll('"', '').replaceAll("'", '').trim();
      rhs = _expandInchFractions(rhs);
      // ASCII fraction like "1/2" or "3/4" → decimal
      final asciiMatch = RegExp(r'^(\d+)/(\d+)$').firstMatch(rhs);
      if (asciiMatch != null) {
        final num = int.tryParse(asciiMatch.group(1)!) ?? 0;
        final den = int.tryParse(asciiMatch.group(2)!) ?? 1;
        if (den != 0) {
          // Match the "0.5" → ".5" convention used by _expandInchFractions
          rhs = (num / den).toString().replaceFirst(RegExp(r'^0(?=\.)'), '');
        }
      }
      if (RegExp(r'^\d*\.?\d+$').hasMatch(rhs) && rhs.isNotEmpty) out.add(rhs);
      continue;
    }
    final up = w.toUpperCase();
    if (up.startsWith('DN') && RegExp(r'\d').hasMatch(w)) {
      for (final part in up.replaceAll(RegExp(r'[^0-9/]'), '').split('/')) {
        if (part.length >= 2) out.add(part);
      }
    } else if (RegExp(r'^\d').hasMatch(w) && w.contains('/')) {
      for (final part in w.replaceAll('"', '').split('/')) {
        if (part.length >= 2 && RegExp(r'^\d+$').hasMatch(part)) out.add(part);
      }
    } else if (w.contains('"') && RegExp(r'\d').hasMatch(w)) {
      final t = w.replaceAll('"', '');
      if (t.length >= 2) out.add(t);
    } else if (RegExp(r'^\d*\.\d+$').hasMatch(w)) {
      out.add(w); // inch decimal from a fraction (1.25 · 1.5 · 2.5)
    }
  }
  return out.toList();
}

